export const lpic2_quiz_pool = [
  // Topic 200: Capacity Planning
  { id: 'lpic2-200-1', topicId: 1, question: 'Какая команда предоставляет динамическое представление системы и работающих процессов в реальном времени, выделяя загрузку ЦП и памяти?', options: ['free', 'top', 'uptime', 'vmstat'], answer: 1, explanation: 'Команда `top` обеспечивает представление процессов в реальном времени.' },
  { id: 'lpic2-200-2', topicId: 1, question: 'Какую из следующих команд вы бы использовали для просмотра подробной статистики ввода/вывода (I/O) для блочных устройств?', options: ['vmstat', 'iostat', 'netstat', 'mpstat'], answer: 1, explanation: 'Команда `iostat` используется для мониторинга нагрузки на устройства ввода/вывода.' },
  { id: 'lpic2-200-3', topicId: 1, question: 'Вы хотите собирать и визуализировать тенденции производительности системы за несколько месяцев. Какой инструмент наиболее подходит?', options: ['top', 'ss', 'Collectd/MRTG/Cacti', 'tcpdump'], answer: 2, explanation: 'Collectd, MRTG и Cacti — это стандартные инструменты, предназначенные для сбора данных с течением времени и создания графиков планирования ресурсов.' },
  { id: 'lpic2-200-4', topicId: 1, question: 'С помощью какого инструмента можно прогнозировать будущие потребности в пропускной способности сети на основе текущих тенденций?', options: ['mrtg', 'ping', 'fsck', 'ls'], answer: 0, explanation: 'MRTG (Multi Router Traffic Grapher) используется для мониторинга сетевого трафика и нагрузки на протяжении времени.' },
  { id: 'lpic2-200-5', topicId: 1, question: 'Какова основная цель команды `sar`?', options: ['Поиск скрытых файлов', 'System Activity Reporter (Информирует об активности системы)', 'Бэкап конфигурации', 'Завершение сетевых процессов'], answer: 1, explanation: 'Утилита `sar` из пакета sysstat служит для автоматического исторического сбора статистики аппаратных нагрузок.' },

  // Topic 201: Linux Kernel
  { id: 'lpic2-201-1', topicId: 2, question: 'Где по умолчанию находятся скомпилированные модули ядра в файловой системе?', options: ['/boot/modules/', '/lib/modules/$(uname -r)/', '/etc/kernel/', '/var/lib/modules/'], answer: 1, explanation: 'Модули хранятся в `/lib/modules/` в папке, соответствующей результату команды uname -r (версии ядра).' },
  { id: 'lpic2-201-2', topicId: 2, question: 'Какая цель (target) команды `make` используется для создания сжатого современного образа ядра?', options: ['make zImage', 'make bzImage', 'make vmlinux', 'make install'], answer: 1, explanation: '`make bzImage` собирает "Big zImage", обходя архитектурные ограничения старого формата zImage.' },
  { id: 'lpic2-201-3', topicId: 2, question: 'Какая команда предоставляет текстовый интерфейс с меню для конфигурации исходников ядра?', options: ['make config', 'make menuconfig', 'make xconfig', 'make defconfig'], answer: 1, explanation: '`make menuconfig` требует библиотеку ncurses для отображения консольного меню конфигурации.' },
  { id: 'lpic2-201-4', topicId: 2, question: 'Какая команда автоматически загружает и разрешает зависимости модуля ядра?', options: ['insmod', 'modinfo', 'modprobe', 'rmmod'], answer: 2, explanation: 'В отличие от insmod, `modprobe` автоматически подгружает все требуемые зависимости модуля.' },
  { id: 'lpic2-201-5', topicId: 2, question: 'Для чего необходим файл `System.map` в загрузке ядра Linux?', options: ['Карта разделов жесткого диска', 'Карта адресов символов ядра (Symbol Table) для отладки', 'Резервная копия MBR', 'Файл хранения паролей root'], answer: 1, explanation: 'Этот файл сопоставляет функции ядра с адресами в памяти для отладчиков и диагностики System Panic.' },

  // Topic 202: System Startup
  { id: 'lpic2-202-1', topicId: 3, question: 'Где в устаревшей системе инициализации SysVinit устанавливается уровень выполнения (Runlevel) по умолчанию?', options: ['/etc/inittab', '/etc/runlevel', '/boot/grub/grub.cfg', '/etc/init.d/rcS'], answer: 0, explanation: 'В SysVinit файл `/etc/inittab` определяет initdefault runlevel.' },
  { id: 'lpic2-202-2', topicId: 3, question: 'С помощью какого скрипта в семействе Debian/Ubuntu обычно заново генерируют конфигурационный файл загрузчика GRUB 2 после изменения параметров ядра?', options: ['grub-install', 'grub2-mkconfig', 'update-grub', 'grub-setup'], answer: 2, explanation: 'Скрипт-обертка `update-grub` запускает grub-mkconfig на Debian-подобных дистрибутивах.' },
  { id: 'lpic2-202-3', topicId: 3, question: 'Для запуска в изолированном однопользовательском режиме (Single-User Mode) под управлением systemd, какой Target следует передать?', options: ['runlevel1.target', 'rescue.target', 'single.target', 'emergency.target'], answer: 1, explanation: 'Systemd сопоставляет старый runlevel 1 с `rescue.target`.' },
  { id: 'lpic2-202-4', topicId: 3, question: 'Какой путь по умолчанию имеет конечный рабочий конфигурационный файл GRUB 2?', options: ['/boot/grub/grub.conf', '/boot/grub2/grub2.cfg', '/boot/grub/grub.cfg', '/etc/grub.cfg'], answer: 2, explanation: 'Обычно файл параметров и меню генерируется в `/boot/grub/grub.cfg`.' },
  { id: 'lpic2-202-5', topicId: 3, question: 'При добавлении аргумента `init=/bin/sh` в конфигурации загрузки ядра GRUB, что произойдет?', options: ['Ядро обходит systemd/init и напрямую предоставляет командную оболочку (root shell).', 'Система загружается через сеть (PXE).', 'Стирается System.map.', 'Поднимается графический интерфейс без сети.'], answer: 0, explanation: 'Этот аргумент подменяет PID 1 на базовую оболочку, давая немедленный доступ с правами root для сброса пароля.' },

  // Topic 203: Filesystem and Devices
  { id: 'lpic2-203-1', topicId: 4, question: 'Какая файловая система, глубоко использующая экстенты (extents) и известная своей высокой масштабируемостью, стала стандартной для RHEL 7+?', options: ['ext4', 'xfs', 'btrfs', 'zfs'], answer: 1, explanation: 'Файловая система XFS широко поддерживается Red Hat для высокопроизводительных хранилищ уровня предприятия.' },
  { id: 'lpic2-203-2', topicId: 4, question: 'Какая команда используется для сканирования жесткого диска и проверки на наличие ошибок или повреждений блоков в файловой системе EXT4?', options: ['fsck.ext4', 'e2fsck', 'A и B', 'xfs_repair'], answer: 2, explanation: '`fsck.ext4` является алиасом или оберткой для утилиты нижнего уровня `e2fsck`.' },
  { id: 'lpic2-203-3', topicId: 4, question: 'Каково основное предназначение файла конфигурации `/etc/fstab`?', options: ['Задает параметры сетевых карт.', 'Регистрация точек монтирования статических файловых систем по умолчанию во время загрузки системы.', 'Хранение ключей доступа SSH.', 'Контроль Iptables.'], answer: 1, explanation: 'File System Table содержит правила автомонтирования дисковых партиций при старте хоста.' },
  { id: 'lpic2-203-4', topicId: 4, question: 'В утилите `smartctl`, какой параметр быстро запрашивает краткий статус работоспособности накопителя (PASSED/FAILED)?', options: ['-a', '-H', '-i', '-t short'], answer: 1, explanation: 'Параметр `-H` (Health) возвращает глобальный встроенный системный статус здоровья винчестера.' },
  { id: 'lpic2-203-5', topicId: 4, question: 'С помощью какого инструмента мы создаем бинарный посекторный дамп всего диска CD-ROM и сохраняем его как `.ISO` файл?', options: ['tar -cvf image.iso /dev/cdrom', 'dd if=/dev/cdrom of=image.iso', 'mkisofs -o image.iso /dev/cdrom', 'cp /dev/cdrom /iso'], answer: 1, explanation: 'Утилита `dd` осуществляет точное побайтовое копирование исходного файла блока `if=` в целевой `of=`.' },

  // Subset of the remaining modules (Translated to RU)
  { id: 'lpic2-204-1', topicId: 5, question: 'Какая стандартная утилита командной строки в Linux применяется для создания и поддержки программных RAID-массивов?', options: ['lvm', 'fdisk', 'mdadm', 'parted'], answer: 2, explanation: '`mdadm` (Multiple Device Admin) отвечает за управление Linux-совместимыми софтверными массивами (RAID).' },
  { id: 'lpic2-204-2', topicId: 5, question: 'Какой уровень RAID реализует исключительно "зеркалирование" данных (Mirroring) без их фрагментации (Striping)?', options: ['RAID 0', 'RAID 1', 'RAID 5', 'RAID 10'], answer: 1, explanation: 'RAID 1 обеспечивает избыточность точной копией всех блоков первого диска на второй.' },
  { id: 'lpic2-204-3', topicId: 5, question: 'Какая команда LVM навсегда расширяет "Группу Томов" (Volume Group), добавляя новый физический диск?', options: ['pvcreate', 'vgextend', 'lvextend', 'vgcreate'], answer: 1, explanation: 'Команда `vgextend` связывает недавно инициированный диск (Physical Volume) с существующей группой.' },
  { id: 'lpic2-204-4', topicId: 5, question: 'Какой параметр утилиты `hdparm` проводит замер чистой скорости чтения диска, игнорируя дисковый кэш.', options: ['-T', '-S', '-t', '-y'], answer: 2, explanation: 'Флаг `-t` говорит утилите проводить тесты чтения с буферизованных секторов диска без обращения к системному кэшу.' },
  { id: 'lpic2-204-5', topicId: 5, question: 'Для чего в основном предназначен протокол "iSCSI"?', options: ['Брандмауэр веб-запросов.', 'Инкапсуляция команд накопителей SCSI в стандартные сетевые пакеты TCP/IP.', 'Расшифровка паролей.', 'Проверка файлов логов.'], answer: 1, explanation: 'iSCSI передает блочные команды хранилищ (SAN) через стандартную сетевую архитектуру (Ethernet).' },

  { id: 'lpic2-205-1', topicId: 6, question: 'С помощью какой команды из современного пакета `iproute2` можно просмотреть кеш соседей (таблицу ARP)?', options: ['arp -n', 'ip neigh show', 'netstat -rn', 'route -n'], answer: 1, explanation: 'Команда `ip neigh` заменяет `arp` для отображения ARP-записей соседних узлов.' },
  { id: 'lpic2-205-2', topicId: 6, question: 'Какая команда из набора `iproute2` показывает действующую таблицу маршрутизации системы?', options: ['route', 'ip route show', 'netstat -r', 'ifconfig'], answer: 1, explanation: '`ip route show` вытеснил старое приложение `route`.' },
  { id: 'lpic2-205-3', topicId: 6, question: 'Что произойдет, если к команде `ping` добавить ключ `-c 4`?', options: ['Отправит пинги четырем разным хостам', 'Отправит ровно 4 пакета Echo Request и завершит работу', 'Пропингует порт номер 4', 'Перейдет на протокол IPv6'], answer: 1, explanation: 'Опция `-c` устанавливает жесткое количество (count) отправляемых ICMP пакетов.' },
  { id: 'lpic2-205-4', topicId: 6, question: 'Какой надежный консольный инструмент повсеместно применяется системными администраторами как "сниффер" (sniffer) для захвата и анализа сетевых пакетов?', options: ['wireshark', 'nmap', 'tcpdump', 'tracepath'], answer: 2, explanation: '`tcpdump` фильтрует и захватывает пакеты прямо из консоли в реальном времени.' },
  { id: 'lpic2-205-5', topicId: 6, question: 'На каком стандартном порту TCP серверы обычно принимают и обслуживают шифрованный веб-трафик (HTTPS)?', options: ['80', '21', '22', '443'], answer: 3, explanation: 'Протокол HTTP поверх TLS (HTTPS) по умолчанию использует порт 443.' },

  { id: 'lpic2-206-1', topicId: 7, question: 'При компиляции проекта на языке "C" из файлов исходного кода (tarball), в каком историческом порядке обычно выполняются команды?', options: ['make > make install > ./configure', './configure > make > make install', 'make install > ./configure > make', 'untar > make install > ./configure'], answer: 1, explanation: 'Сначала `./configure` подготавливает сборочную среду, затем `make` компилирует бинарники, а `make install` расставляет их в системе.' },
  { id: 'lpic2-206-2', topicId: 7, question: 'Укажите приложение командной строки, созданное для высокоэффективной синхронизации удаленных директорий, передающее лишь измененные блоки битов, а не целые файлы?', options: ['cp', 'scp', 'ftp', 'rsync'], answer: 3, explanation: 'Rsync использует продвинутый алгоритм вычисления "дельты" файлов.' },
  { id: 'lpic2-206-3', topicId: 7, question: 'Какую основную функцию выполняет команда отладки `strace`?', options: ['Сканирует уязвимости портов', 'Перехватывает и протоколирует системные вызовы (System Calls) и сигналы процессов', 'Ищет руткиты на дисках', 'Читает переменные среды'], answer: 1, explanation: '`strace` помогает отладить недоступность файлов и нарушения прав, отслеживая коммуникацию процесса с ядром ядра.' },
  { id: 'lpic2-206-4', topicId: 7, question: 'Какой командой системный администратор может мгновенно вывести список всех используемых процессов и заблокированных дескрипторов файлов (в т.ч. TCP-сокетов)?', options: ['lsof', 'ps', 'top', 'find'], answer: 0, explanation: 'Команда `lsof` (List Open Files) отображает кем и чем блокируется устройство файла.' },
  { id: 'lpic2-206-5', topicId: 7, question: 'Какой традиционный набор ключей команды `tar` разархивирует файл формата .tar.gz с выводом имен файлов на экран?', options: ['-cvf', '-xvf', '-zxvf', '-jcvf'], answer: 2, explanation: '-z вызывает Gzip для расшифровки, -x разархивация, -v подробный список (verbose), -f сам архивный файл.' },

  { id: 'lpic2-207-1', topicId: 8, question: 'Какой ресурсный тип (Record Type) в конфигурации DNS BIND используется для непосредственного преобразования имени (FQDN) в сетевой адрес стандарта IPv4?', options: ['MX', 'CNAME', 'A', 'AAAA'], answer: 2, explanation: 'Тип "A" (Address Record) сопоставляет домены с интернет протоколом IPv4.' },
  { id: 'lpic2-207-2', topicId: 8, question: 'Какой утилитой проверяют целостность и синтаксис файла описывающего зону DNS (Zone file) перед рестартом сервиса?', options: ['named-checkconf', 'named-checkzone', 'dns-lint', 'dig'], answer: 1, explanation: 'Утилита `named-checkzone` парсит и подтверждает что синтаксис зоны лишен опечаток.' },
  { id: 'lpic2-207-3', topicId: 8, question: 'Чему служит MX-запись (MX Record) в доменной зоне?', options: ['Балансировке веб-серверов в CNAME.', 'Указывает почтовые шлюзы и серверы адресата (Mail Exchangers), которые вправе принимать почтовые письма за этот домен.', 'Управление DDNS пулами.', 'Доставка ключей аутентификации SPF.'], answer: 1, explanation: 'Она расставляет веса SMTP-маршрутам для входящей корреспонденции корпорации.' },
  { id: 'lpic2-207-4', topicId: 8, question: 'С помощью какого стандарта защиты предотвращаются атаки отравления кэша (DNS Spoofing), использующего несимметричную сертификацию для подписи ответов сервера DNS?', options: ['DNS-Over-HTTPS (DoH)', 'TLS', 'DNSSEC', 'TSIG'], answer: 2, explanation: 'Структура DNSSEC снабжает каждый ответ сервера цифровыми подписями для подтверждения истинного источника.' },
  { id: 'lpic2-207-5', topicId: 8, question: 'В каком абсолютном пути преимущественно находится основной заголовочный файл конфигураций демона BIND в системах Linux/UNIX?', options: ['/etc/bind/bind.conf', '/etc/named.conf', '/var/named/config', '/etc/resolv.conf'], answer: 1, explanation: 'Традиционно, службы BIND именуются "named", а точка входа лежит в `/etc/named.conf`.' },

  { id: 'lpic2-208-1', topicId: 9, question: 'Какая конструкция в конфигурации Apache HTTPD позволяет обслуживать абсолютно разные веб-сайты и домены на одном IP-адресе или сервере?', options: ['<Directory>', '<ServerHost>', '<VirtualHost>', '<Website>'], answer: 2, explanation: 'Концепция `<VirtualHost>` позволяет связывать разные конфигурации и каталоги с портами или веб-доменами пользователей.' },
  { id: 'lpic2-208-2', topicId: 9, question: 'Что является архитектурным преимуществом Nginx, сделавшим его самым популярным выбором для создания высоконагруженных прокси и балансировщиков?', options: ['Встроенная поддержка баз данных MySQL.', 'Асинхронная неблокирующая архитектура (Event-Driven), которая легко держит тысячи одновременных подключений как обратный прокси.', 'Игнорирование правил файервола ядра.', 'Трансляция L2 кадров.'], answer: 1, explanation: 'Благодаря управляемой событийностями модели (Event Loops), Nginx почти не исчерпывает ресурсы CPU, маршрутизируя запросы к backend серверам.' },
  { id: 'lpic2-208-3', topicId: 9, question: 'В качестве чего системные администраторы преимущественно устанавливают службу SQUID на корпоративном шлюзе?', options: ['Блокировка SMTP спама.', 'Прокси-сервис для кэширования веб-страниц пользователей в целях экономии трафика и применения правил изоляции интернета по Access Control Lists.', 'Репозиторий гипервизоров.', 'Узел VPN-сети.'], answer: 1, explanation: 'SQUID кэширует HTTP/HTTPS объекты и может ограничивать к ним доступ для рабочих станций изнутри LAN.' },
  { id: 'lpic2-208-4', topicId: 9, question: 'Какое официальное расширение встраивает криптографию OpenSSL в ядро Apache для корректного обеспечения безопасности (HTTPS 443)?', options: ['mod_rewrite', 'mod_security', 'mod_ssl', 'mod_proxy'], answer: 2, explanation: 'Компонент `mod_ssl` заведует импортом сертификатов и ключей для шифрования веб-маршрута.' },
  { id: 'lpic2-208-5', topicId: 9, question: 'На каком TCP-порту "с завода" установлен на ожидание подключений SQUID Proxy Server?', options: ['80', '443', '3128', '8080'], answer: 2, explanation: 'По умолчанию слушающим портом утилиты SQUID назначен сокет конфигурации TCP: 3128.' },

  { id: 'lpic2-209-1', topicId: 10, question: 'С помощью какого комплекса служб происходит успешная сетевая эмуляция доменного и файлового протоколов от компании Microsoft (SMB/CIFS) в среде Linux?', options: ['NFS', 'Samba', 'FTP', 'SSHFS'], answer: 1, explanation: 'Набор Samba позволяет компьютерам с Unix/Linux свободно обмениваться ресурсами с Active Directory или Workgroup операционных систем Windows.' },
  { id: 'lpic2-209-2', topicId: 10, question: 'В каком корневом конфигурационном файле прописываются общие ресурсы, права доступа и параметры сервера Samba?', options: ['/etc/smb/smb.conf', '/etc/samba/smb.conf', '/usr/local/samba.cfg', '/var/lib/samba/config'], answer: 1, explanation: 'Данным главным узлом управления Samba всегда является `/etc/samba/smb.conf`.' },
  { id: 'lpic2-209-3', topicId: 10, question: 'В сетевой файловой системе NFS, где объявляются списки разрешенных и экспортируемых удаленных каталогов для монтирования клиентами в LAN?', options: ['/etc/exports', '/etc/nfs.conf', '/etc/fstab', '/etc/samba/smb.conf'], answer: 0, explanation: 'В `/etc/exports` вносится директория, IP группы серверов и права доступа на экспорт.' },
  { id: 'lpic2-209-4', topicId: 10, question: 'Какой командой нужно на лету активировать и ресинкронизировать новые правила изменённые в `/etc/exports` без перезагрузки NFS сервиса, во избежание Kernel Panic у текущих активных клиентов?', options: ['nfs-update', 'systemctl reload nfs', 'exportfs -a / -r', 'mount -a'], answer: 2, explanation: 'С помощью команды `exportfs -r` сервер немедленно обновляет кэш экспортных каталогов прозрачно для удаленных машин.' },
  { id: 'lpic2-209-5', topicId: 10, question: 'Базы паролей системы (shadow) и Samba раздельны по шифрованию. Как добавить локальному Linux пользователю соответствующий учетный пароль для удалённого сетевого входа клиентов Samba?', options: ['smbpasswd -a', 'useradd', 'passwd', 'pdbedit -n'], answer: 0, explanation: 'Утилита `smbpasswd -a имя_юзверя` зашифровывает и сохраняет пароль в реестре демона SMB.' },

  { id: 'lpic2-210-1', topicId: 11, question: 'Если нужно автоматически раздавать адреса IPv4/IPv6, шлюз и настройки серверов имен DNS клиентам, то системные администраторы используют стандартную службу:', options: ['DNS', 'DHCP', 'ARP', 'ICMP'], answer: 1, explanation: 'Сервер Dynamic Host Configuration Protocol берет в лизинг адреса сети.' },
  { id: 'lpic2-210-2', topicId: 11, question: 'Каким было переломное предназначение архитектуры "Pluggable Authentication Modules" (PAM) в ядре операционной системы и утилитах аутентификации?', options: ['Отвязка приложений и служб от жестко прописанного кода методов логина. PAM позволяет службам просто отправлять запрос и проверять токен пароля/сертификата, вне зависимости от базового метода (LDAP/SmartCard/Local).', 'Контроль пропускного Iptables трафика.', 'Репликация баз.', 'Снятие ограничения файловых квот.'], answer: 0, explanation: 'PAM делает модули аутентификации независимыми от перекомпиляции ПО. Программе SSH или Login не нужно знать как расшифровать LDAP базу, всё решает PAM.' },
  { id: 'lpic2-210-3', topicId: 11, question: 'Какова применимость протокола доступа к каталогам (LDAP) в современных сетевых корпорациях?', options: ['Как масштабируемый и оптимизированный для ускоренных запросов на чтение распределенный корпоративный справочник сотрудников, списков почты и централизованная база идентичностей ролей.', 'Физическое резервное копирование дисков.', 'Маршрутизация OSPF.', 'Трансляция VPN потоков.'], answer: 0, explanation: 'Часто работает как база-агрегатор организационных данных (Directory Information Tree) для сотрудников в домене.' },
  { id: 'lpic2-210-4', topicId: 11, question: 'Используя интерфейс виртуального контроллера "TUN" в конфигурации моста туннелирования OpenVPN, в какой модели (OSI Layer) оперорует созданное звено связи?', options: ['OSI Layer-1, Уровень аппаратного медиа.', 'Только Уровень Сети (Layer-3 IP Routing), пересылая лишь защищённые IP-пакеты и заголовки маршрутов.', 'MAC Bridge L2 Layer.', 'В прикладном HTTP слое Layer 7.'], answer: 1, explanation: 'Концепция интерфейса `TUN` обрезает лишний Broadcast фрейминг уровня Ethernet маков (которые есть в TAP) и маршрутизирует исключительно чистые IP пакеты.' },
  { id: 'lpic2-210-5', topicId: 11, question: 'Из практики, какой стандартный UDP сокет назначен интернет стандартом IANA сервису и серверу OpenVPN "из коробки" для прослушиваний?', options: ['1194 UDP', '22 TCP', '443 TCP', '53 UDP'], answer: 0, explanation: 'В режиме по умолчанию, OpenVPN настроен на порт 1194 протокола UDP на стороне сервера и на стороне клиента.' },

  { id: 'lpic2-211-1', topicId: 12, question: 'Какой официальный протокол обмена и передачи используется агентами "MTA" (Postfix, Exim, Sendmail) для ретрансляции и доставки электронных писем по цепочке серверов "до порога"?', options: ['POP3', 'IMAP', 'SMTP', 'SNMP'], answer: 2, explanation: 'Менеджер Simple Mail Transfer Protocol заведует общением сервер-к-серверу для доставки контента в сети Интернет.' },
  { id: 'lpic2-211-2', topicId: 12, question: 'Какому текстовому конфигурационному файлу принадлежит роль основного мозга и архитектурных политик демона POSTFIX (определяющему фильтры, алиасы, ограничение по доверенным IPS сетей)?', options: ['/etc/postfix/master.cf', '/etc/postfix/main.cf', '/etc/mail/sendmail.cf', '/var/spool/postfix/config'], answer: 1, explanation: 'Несмотря на то, что `master.cf` управляет порождением служб, вся главная тонкая настройка маршрутизатора и фильтрации спама зафиксирована в `/etc/postfix/main.cf`.' },
  { id: 'lpic2-211-3', topicId: 12, question: 'Назовите современный де-факто "золотой стандарт" открытого сервера (IMAP/POP3) под Linux для предоставления конечным Mail-клиентам удаленного доступа к их папкам с письмами в папках хоста?', options: ['Postfix', 'Dovecot', 'Procmail', 'Squid'], answer: 1, explanation: 'Dovecot Server крайне надёжно, асинхронно и быстро вычитывает сообщения с хранилищ и передает их Outlook/Mobile-приложениям по почтовым защищённым протоколам.' },
  { id: 'lpic2-211-4', topicId: 12, question: 'Для решения каких администраторских почтовых задач внедряются локальные агенты доставки (MDA), такие как Procmail или правила скриптов Sieve?', options: ['Проведение финального локального контроля: перехват письма перед записью на диск, применение Regex фильтров, перенаправление спама и сортировка в подпапки инбокса пользователя.', 'Настройка VPN аутентификации.', 'Проверка загруженности DNS.', 'Модуль прокси Squid.'], answer: 0, explanation: 'Sieve и Procmail осуществляют последнюю милю (Local Delivery), обеспечивая возможности фильтраций почты (переместить в "Нежелательное" если X-SPAM flag = ON).' },
  { id: 'lpic2-211-5', topicId: 12, question: 'Как в Sendmail, так и в Postfix, после редактирования вами файла псевдонимов /etc/aliases, какой встроенный инструмент системному администратору нужно запустить для трансляции изменений Алиасов в формат бинарного словаря DB?', options: ['makemap', 'newaliases', 'postmap', 'systemctl reload postfix'], answer: 1, explanation: 'Оригинальный обработчик `newaliases` собирает и компилирует исходник таблицы перенаправлений почт в оптимизированную .db карту.' },

  { id: 'lpic2-212-1', topicId: 13, question: 'В архитектуре IPTables (внутри механизма Netfilter), в какой специализированной "таблице" (TABLE) обрабатываются перенаправления пакетов (Port Forwarding), сокрытие внутренних сетей и прочие метаморфозы с адресатами и источниками (SNAT/DNAT)?', options: ['filter', 'mangle', 'nat', 'raw'], answer: 2, explanation: 'Таблица "nat" разработана исключительно для правил Network Address Translation (подмена IP-адресов источника или назначения).' },
  { id: 'lpic2-212-2', topicId: 13, question: 'Какая резидентная программа-скрипт Linux реагирует на агрессивные попытки атак (Brute-Force Attackers) сканируя файлы логов авторизаций (/var/log/secure) и оперативно внедряя изолирующие временные баны напрямую в Firewall?', options: ['Snort / Suricata', 'Fail2ban', 'Nmap', 'OpenVAS/Nessus'], answer: 1, explanation: 'Fail2Ban динамично контролирует логи веб-серверов или ssh, временно накладывая DROP IP-Tables правила против сканеров хакеров.' },
  { id: 'lpic2-212-3', topicId: 13, question: 'В рамках пентестов, укажите название знаменитой консольной утилиты, которую киберспециалисты применяют для картографирования сетей (Discovery), определения ОС и широкого сканирования прослушиваемых версий портов.', options: ['tcpdump stream capture', 'wireshark analizer LAN', 'nmap host & versions mapping scanner tool', 'ping sweeping scanner'], answer: 2, explanation: 'Утилита Network Mapper (Nmap) агрессивно, либо в "Стелс-режиме", выясняет топологию портов и сервисов удаленного серверного парка.' },
  { id: 'lpic2-212-4', topicId: 13, question: 'Какая корпоративная система аудита и сканирования уязвимостей, отделившаяся от закрытой ветки ПО Nessus, поставляется в качестве сервера GVM (Greenbone Vulnerability Manager)?', options: ['Автокликер для консоли.', 'Проект "OpenVAS" Vulnerability Assessment System', 'Браузер Tor.', 'Детектор Smart-Hardware.'], answer: 1, explanation: 'Сервер OpenVAS автоматически сверяет целевые серверы с глобальным каталогом уязвимостей CVE/Secunia, выполняя реальные безопасные попытки переполнения буфера или проверки просрочек паролей.' },
  { id: 'lpic2-212-5', topicId: 13, question: 'Какова конечная цель настройки атрибута `-P` (Policy) из конструкции `iptables -P INPUT DROP` для секции входящего трафика таблицы Filter?', options: ['iptables -A INPUT -j DROP', 'Устанавливает базовое и абсолютное правило "по умолчанию": если трафик не получил допуск "ALLOW" ранее, брандмауэр его молча и полностью уничтожает.', 'iptables -I INPUT DROP', 'iptables -D INPUT DROP'], answer: 1, explanation: 'Этот атрибут задает "ПОЛИТИКУ ПО УМОЛЧАНИЮ" для всей цепочки. DROP означает максимальную начальную закрытость и безопасность.' },
  // --- NEW BATCH 1 (Topics 200-204) ---
  { id: 'lpic2-200-6', topicId: 1, question: 'В выводе `vmstat`, что означает колонка `wa`?', options: ['Ожидание CPU (Waiting for CPU)', 'Ожидание ввода/вывода (Waiting for I/O)', 'Ожидание сети (Waiting for network)', 'Ожидание выделения памяти'], answer: 1, explanation: 'Колонка `wa` в `vmstat` показывает процент времени CPU, затраченного на ожидание завершения операций ввода/вывода.' },
  { id: 'lpic2-200-7', topicId: 1, question: 'Какая команда предоставляет быструю сводку средних значений загрузки системы (load averages) за последние 1, 5 и 15 минут?', options: ['w', 'uptime', 'Обе (A и B)', 'sar'], answer: 2, explanation: 'Обе команды `w` и `uptime` отображают средние значения загрузки системы.' },
  { id: 'lpic2-200-8', topicId: 1, question: 'Какой основной протокол использует MRTG для сбора данных с сетевых устройств?', options: ['SSH', 'SMTP', 'SNMP', 'HTTP'], answer: 2, explanation: 'MRTG (Multi Router Traffic Grapher) в основном полагается на SNMP (Simple Network Management Protocol) для сбора метрик.' },
  { id: 'lpic2-200-9', topicId: 1, question: 'Какая команда показывает статистику сетевых интерфейсов, включая отброшенные пакеты (dropped packets) и переполнения (overruns)?', options: ['netstat -i', 'netstat -r', 'netstat -tulnp', 'ifconfig -a'], answer: 0, explanation: '`netstat -i` отображает таблицу всех сетевых интерфейсов и их статистики передачи/приема.' },
  { id: 'lpic2-200-10', topicId: 1, question: 'Какое значение памяти в выводе команды `free` наиболее точно указывает на память, доступную для запуска новых приложений без использования файла подкачки (swapping)?', options: ['total', 'used', 'shared', 'available'], answer: 3, explanation: 'Колонка `available` оценивает, сколько памяти доступно для запуска новых приложений без физического своппинга.' },
  { id: 'lpic2-200-11', topicId: 1, question: 'Как настроить Collectd для эффективного хранения метрик с течением времени?', options: ['Писать в CSV', 'Писать в RRDtool', 'Писать только в MySQL', 'Писать в syslog'], answer: 1, explanation: 'Collectd часто использует плагин RRDtool (Round Robin Database) для эффективного хранения данных временных рядов.' },
  { id: 'lpic2-200-12', topicId: 1, question: 'Какой инструмент специально создан для отображения в реальном времени использования I/O для каждого процесса аналогично `top`?', options: ['iotop', 'iostat', 'ioping', 'blktrace'], answer: 0, explanation: '`iotop` отображает пользовательский интерфейс в стиле top, показывающий пропускную способность чтения и записи I/O для каждого процесса.' },
  { id: 'lpic2-200-13', topicId: 1, question: 'На что убедительно указывают высокие значения `si` и `so` в `vmstat`?', options: ['Перегрузка сети', 'Узкое место CPU (bottleneck)', 'Нехватка памяти и интенсивный своппинг', 'Аппаратный сбой диска'], answer: 2, explanation: 'Высокие показатели Swap In (`si`) и Swap Out (`so`) указывают на то, что система активно использует диск для подкачки из-за исчерпания RAM.' },
  { id: 'lpic2-200-14', topicId: 1, question: 'Какая команда выводит список всех прослушивающих TCP и UDP сокетов вместе с PID процесса?', options: ['ss -tulnp', 'netstat -rn', 'ip route', 'arp -a'], answer: 0, explanation: '`ss -tulnp` (или netstat -tulnp) выводит список прослушивающих портов TCP/UDP и связанные Process ID.' },
  { id: 'lpic2-200-15', topicId: 1, question: 'При планировании ресурсов (capacity planning), что такое "базовый уровень" (baseline)?', options: ['Максимальная вместимость сервера', 'Минимальный объем RAM, необходимый для загрузки', 'Исторические данные, представляющие нормальное поведение системы', 'Физический предел сетевой карты'], answer: 2, explanation: 'Базовый уровень — это известное, нормальное состояние системы, записанное с течением времени, для сравнения с аномалиями или будущим ростом.' },

  { id: 'lpic2-201-6', topicId: 2, question: 'Какая команда полностью очищает дерево исходного кода ядра, удаляя все скомпилированные файлы и файл .config?', options: ['make clean', 'make mrproper', 'make distclean', 'make wipe'], answer: 1, explanation: '`make mrproper` удаляет все сгенерированные файлы, включая `.config` и различные резервные копии, обеспечивая чистое дерево исходников.' },
  { id: 'lpic2-201-7', topicId: 2, question: 'Каково назначение команды `depmod`?', options: ['Удалить модуль', 'Сгенерировать файл modules.dep для modprobe', 'Просмотр сведений о модуле', 'Компиляция модулей'], answer: 1, explanation: '`depmod` обследует модули ядра и генерирует список зависимостей (`modules.dep`), который использует `modprobe`.' },
  { id: 'lpic2-201-8', topicId: 2, question: 'Какой инструмент динамически перестраивает модули ядра для сторонних драйверов (например, Nvidia) при установке нового ядра?', options: ['depmod', 'dracut', 'DKMS', 'kmod'], answer: 2, explanation: 'DKMS (Dynamic Kernel Module Support) — это фреймворк, который перекомпилирует внешние модули ядра при установке нового ядра.' },
  { id: 'lpic2-201-9', topicId: 2, question: 'Как просмотреть текущую активную конфигурацию запущенного ядра (если поддерживается ядром)?', options: ['cat /proc/kcore', 'zcat /proc/config.gz', 'cat /sys/kernel/config', 'dmesg | grep config'], answer: 1, explanation: 'Если опция `IKCONFIG_PROC` включена, конфигурация запущенного ядра доступна по адресу `/proc/config.gz`.' },
  { id: 'lpic2-201-10', topicId: 2, question: 'Какая команда выводит список всех загруженных в данный момент модулей ядра?', options: ['lsmod', 'modinfo', 'modprobe -l', 'infomod'], answer: 0, explanation: '`lsmod` форматирует содержимое `/proc/modules`, показывая, какие модули ядра загружены в память в данный момент.' },
  { id: 'lpic2-201-11', topicId: 2, question: 'В чем основное различие между `initrd` и `initramfs`?', options: ['initrd — это архив cpio; initramfs — образ блочного устройства', 'initramfs — это архив cpio, извлеченный в tmpfs; initrd — образ блочного устройства', 'initrd предназначен только для UEFI', 'initramfs не может загружать модули'], answer: 1, explanation: '`initramfs` — это современный, более простой подход с использованием сжатого архива cpio, загруженного в tmpfs, позволяющий избежать использования драйверов блочных устройств на ранних этапах загрузки.' },
  { id: 'lpic2-201-12', topicId: 2, question: 'Какая команда отображает информацию о модуле ядра (автор, описание, параметры)?', options: ['lsmod', 'modprobe -d', 'modinfo', 'insmod -i'], answer: 2, explanation: '`modinfo` извлекает и выводит информацию непосредственно из объектного файла модуля.' },
  { id: 'lpic2-201-13', topicId: 2, question: 'Какая команда считывает `sysctl.conf` и немедленно применяет параметры ядра?', options: ['sysctl -w', 'sysctl -a', 'sysctl -p', 'sysctl -r'], answer: 2, explanation: '`sysctl -p` загружает параметры конфигурации из `/etc/sysctl.conf` (или указанного файла) в работающее ядро.' },
  { id: 'lpic2-201-14', topicId: 2, question: 'Где `udev` ищет свои пользовательские правила событий оборудования?', options: ['/etc/udev/rules.d/', '/lib/udev/rules.d/', 'Оба варианта (A и B)', '/var/run/udev/'], answer: 2, explanation: '`udev` считывает правила по умолчанию из `/lib/udev/rules.d/` и пользовательские правила администратора из `/etc/udev/rules.d/`.' },
  { id: 'lpic2-201-15', topicId: 2, question: 'Какая команда удаляет модуль ядра из запущенного ядра, если он больше не используется?', options: ['rmmod', 'insmod -r', 'modprobe -r', 'A и C'], answer: 3, explanation: 'Обе команды `rmmod` и `modprobe -r` могут использоваться для удаления модулей, хотя `modprobe -r` также чисто удаляет неиспользуемые зависимости.' },

  { id: 'lpic2-202-6', topicId: 3, question: 'В systemd, какая команда устанавливает цель по умолчанию на Graphical (эквивалент runlevel 5)?', options: ['systemctl set-default graphical.target', 'systemctl isolate graphical.target', 'systemctl default graphical.target', 'ln -s /lib/systemd/system/graphical.target /etc/inittab'], answer: 0, explanation: '`systemctl set-default` изменяет цель загрузки по умолчанию, обновляя символическую ссылку `/etc/systemd/system/default.target`.' },
  { id: 'lpic2-202-7', topicId: 3, question: 'Во время загрузки GRUB 2, какая клавиша обычно открывает меню загрузки для редактирования параметров ядра, если оно скрыто?', options: ['F8', 'F12', 'Shift или Esc', 'Enter'], answer: 2, explanation: 'Удержание `Shift` (для BIOS) или нажатие `Esc` (для UEFI) прерывает процесс загрузки GRUB 2 и открывает меню.' },
  { id: 'lpic2-202-8', topicId: 3, question: 'Что делает команда `systemctl isolate`?', options: ['Перезагружает систему', 'Сразу переключает текущее рабочее состояние на новую цель, останавливая ненужные сервисы', 'Отключает сетевые интерфейсы', 'Переходит в среду chroot'], answer: 1, explanation: '`isolate` немедленно переключает систему на новую цель (target) (как переключение уровней выполнения в SysV).' },
  { id: 'lpic2-202-9', topicId: 3, question: 'В каком файле содержатся глобальные настройки (например, таймаут и запись по умолчанию), используемые grub-mkconfig для создания конфигурации GRUB 2?', options: ['/etc/grub.d/00_header', '/boot/grub/grub.cfg', '/etc/default/grub', '/boot/grub/menu.lst'], answer: 2, explanation: '`/etc/default/grub` содержит переменные, такие как `GRUB_TIMEOUT` и `GRUB_CMDLINE_LINUX`, которые управляют генерацией скрипта.' },
  { id: 'lpic2-202-10', topicId: 3, question: 'Что такое PXE?', options: ['Формат таблицы разделов', 'Метод загрузки ОС по сети с использованием DHCP и TFTP', 'Загрузчик Linux для ARM', 'Тип юнита systemd'], answer: 1, explanation: 'Preboot eXecution Environment (PXE) позволяет сетевым картам получать загрузчик и ядро с сетевого сервера.' },
  { id: 'lpic2-202-11', topicId: 3, question: 'В каком каталоге находятся модульные скрипты, выполняемые `grub-mkconfig`?', options: ['/etc/default/grub', '/etc/grub.d/', '/boot/grub/scripts/', '/lib/grub/'], answer: 1, explanation: 'Каталог `/etc/grub.d/` содержит исполняемые сценарии (например, 10_linux), которые проверяют систему при создании grub.cfg.' },
  { id: 'lpic2-202-12', topicId: 3, question: 'Что такое `systemd-boot`?', options: ['Обертка SysVinit', 'Легковесный менеджер загрузки UEFI', 'Плагин для GRUB', 'Тема Plymouth'], answer: 1, explanation: '`systemd-boot` (ранее gummiboot) — это простой менеджер загрузки UEFI, включенный в состав systemd.' },
  { id: 'lpic2-202-13', topicId: 3, question: 'Если вы потеряли пароль root, какой параметр ядра можно передать в GRUB, чтобы обойти аутентификацию?', options: ['root=/dev/null', 'init=/bin/bash', 'skip_auth=1', 'runlevel=0'], answer: 1, explanation: 'Добавление `init=/bin/bash` (или /bin/sh) монтирует root и немедленно переходит в оболочку с правами root без запроса пароля.' },
  { id: 'lpic2-202-14', topicId: 3, question: 'Какая команда генерирует начальный ramdisk (initramfs) в системах Red Hat / CentOS?', options: ['mkinitcpio', 'mkinitrd / dracut', 'update-initramfs', 'initramfs-build'], answer: 1, explanation: 'Системы на базе RHEL исторически использовали `mkinitrd`, а в настоящее время встроенно используют `dracut` для сборки initramfs.' },
  { id: 'lpic2-202-15', topicId: 3, question: 'В SysVinit какой сценарий обычно отвечает за выполнение скриптов rc для заданного уровня выполнения?', options: ['/etc/rc.local', '/etc/init.d/rc', '/sbin/runlevel', '/bin/sh'], answer: 1, explanation: 'Сценарий `/etc/init.d/rc` вызывается init с уровнем выполнения в качестве аргумента для запуска/остановки соответствующих служб в `/etc/rcX.d/`.' },

  { id: 'lpic2-203-6', topicId: 4, question: 'Какая команда отображает аппаратную геометрию и разделы диска?', options: ['df -h', 'lsblk', 'fdisk -l', 'Оба варианта (B и C)'], answer: 3, explanation: 'И `lsblk`, и `fdisk -l` описывают блочные устройства и разделы (fdisk показывает детали геометрии).' },
  { id: 'lpic2-203-7', topicId: 4, question: 'Какая команда конвертирует файловую систему ext3 в ext4 без потери данных?', options: ['tune2fs -O extents,uninit_bg,dir_index /dev/sda1', 'mkfs.ext4 /dev/sda1', 'fsck.ext4 -y /dev/sda1', 'parted /dev/sda1 convert ext4'], answer: 0, explanation: '`tune2fs` позволяет переключать функции файловой системы на существующем диске; добавление функций ext4 преобразует ее.' },
  { id: 'lpic2-203-8', topicId: 4, question: 'Какой инструмент изменяет UUID файловой системы ext2/ext3/ext4?', options: ['uuidgen', 'blkid', 'tune2fs -U', 'xfs_admin'], answer: 2, explanation: '`tune2fs -U [UUID|random] /dev/sdX` изменяет UUID файловой системы.' },
  { id: 'lpic2-203-9', topicId: 4, question: 'Какая опция в `/etc/fstab` монтирует файловую систему только для чтения?', options: ['rw', 'ro', 'noexec', 'nosuid'], answer: 1, explanation: 'Опция `ro` указывает на монтирование Read-Only.' },
  { id: 'lpic2-203-10', topicId: 4, question: 'Какая команда предоставляет информацию о состоянии и фрагментации файловой системы XFS?', options: ['xfs_repair', 'xfs_info', 'xfs_db', 'Ничего из вышеперечисленного'], answer: 1, explanation: '`xfs_info` печатает геометрию и детали распределения смонтированной файловой системы XFS.' },
  { id: 'lpic2-203-11', topicId: 4, question: 'Как надежно стереть жесткий диск (/dev/sdb), перезаписав его случайными данными?', options: ['dd if=/dev/urandom of=/dev/sdb bs=1M', 'rm -rf /dev/sdb', 'mkfs.ext4 /dev/sdb', 'fdisk -w /dev/sdb'], answer: 0, explanation: '`dd`, выполняющая чтение из `/dev/urandom`, физически перезаписывает целевой диск непредсказуемыми бинарными данными.' },
  { id: 'lpic2-203-12', topicId: 4, question: 'Что делает команда `badblocks`?', options: ['Форматирует диск', 'Сканирует устройство на наличие физически поврежденных секторов', 'Восстанавливает реестр файловой системы', 'Определяет поврежденную RAM'], answer: 1, explanation: '`badblocks` выполняет тесты чтения/записи на секторах для выявления физически непригодных блоков на накопителе.' },
  { id: 'lpic2-203-13', topicId: 4, question: 'Какая команда Btrfs делает снапшот (snapshot) подтома (subvolume) с возможностью чтения и записи?', options: ['btrfs subvolume snapshot', 'btrfs snap create', 'lvcreate -s', 'btrfs-image'], answer: 0, explanation: '`btrfs subvolume snapshot <источник> <цель>` создает снимок Copy-on-Write.' },
  { id: 'lpic2-203-14', topicId: 4, question: 'Что такое `autofs`?', options: ['Инструмент для форматирования дисков', 'Демон, который автоматически монтирует файловые системы по требованию', 'Замена для GRUB', 'Сетевой пакетный маршрутизатор'], answer: 1, explanation: '`autofs` обеспечивает автоматическое монтирование (монтирование только тогда, когда пользователь обращается к определенному каталогу) и автоматическое размонтирование.' },
  { id: 'lpic2-203-15', topicId: 4, question: 'Какая утилита записи оптических носителей создает образ файловой системы ISO9660?', options: ['cdrecord', 'mkisofs', 'growisofs', 'wodim'], answer: 1, explanation: '`mkisofs` (или genisoimage) берет дерево каталогов и генерирует файл структуры ISO9660, пригодный для записи.' },

  { id: 'lpic2-204-6', topicId: 5, question: 'Как в LVM безопасно уменьшить размер логического тома?', options: ['lvresize -L -10G /dev/vg/lv', 'Сначала уменьшить файловую систему внутри LV, затем изменить размер самого LV', 'Сначала изменить размер LV, затем изменить размер файловой системы', 'Уменьшить LV невозможно'], answer: 1, explanation: 'Сначала необходимо сжать файловую систему (например, resize2fs) ДО сжатия LV, чтобы избежать повреждения границ данных.' },
  { id: 'lpic2-204-7', topicId: 5, question: 'При управлении программным массивом RAID 5 с помощью `mdadm`, что произойдет в случае выхода из строя одного диска?', options: ['Данные будут безвозвратно утеряны', 'Массив работает в деградированном (degraded) режиме, используя четность для вычисления отсутствующих данных', 'Немедленная паника ядра (kernel panic)', 'Массив переключается на RAID 0'], answer: 1, explanation: 'RAID 5 может пережить отказ ровно одного диска, работая в «деградированном режиме» до момента перестроения.' },
  { id: 'lpic2-204-8', topicId: 5, question: 'Какая команда инициирует сеанс iSCSI для обнаружения (discovery) целей на сервере?', options: ['iscsiadm -m discovery -t sendtargets -p <IP>', 'iscsid --scan', 'mount -t iscsi', 'lvscan'], answer: 0, explanation: '`iscsiadm` — это инструмент CLI для взаимодействия с инициатором open-iscsi с целью обнаружения и входа (login) на цели.' },
  { id: 'lpic2-204-9', topicId: 5, question: 'Что показывает команда LVM `vgdisplay`?', options: ['Только физические тома', 'Только логические тома', 'Атрибуты групп томов (VG), такие как общий размер, свободные PE и распределенные PE', 'UUID файловых систем'], answer: 2, explanation: '`vgdisplay` выдает метаданные о группах томов, включая сведения о емкости физических экстентов (PE).' },
  { id: 'lpic2-204-10', topicId: 5, question: 'Как добавить резервный (spare) диск в существующий массив `mdadm` RAID (/dev/md0)?', options: ['mdadm --add /dev/md0 /dev/sdX', 'mdadm --grow /dev/md0 --size=spare', 'mdadm --create /dev/md0 /dev/sdX', 'Добавлять spare к активным массивам нельзя'], answer: 0, explanation: 'Флаг `--add` (или `-a`) добавляет запасное устройство в существующий массив «на горячую».' },
  { id: 'lpic2-204-11', topicId: 5, question: 'Каково назначение снимков (snapshots) LVM?', options: ['Создавать постоянные резервные копии на ленту', 'Мгновенно фиксировать состояние логического тома (Copy-on-Write) для резервного копирования', 'Ускорить чтение с диска', 'Конвертировать ext4 в xfs'], answer: 1, explanation: 'Снапшоты отслеживают изменения с помощью CoW, позволяя создавать резервную копию "замороженного" состояния тома на определенный момент времени без простоев.' },
  { id: 'lpic2-204-12', topicId: 5, question: 'В среде iSCSI, что такое IQN?', options: ['Internal Query Network', 'iSCSI Qualified Name', 'Internet Quota Node', 'Initial Queue Number'], answer: 1, explanation: 'iSCSI Qualified Name (IQN) — это глобально уникальный идентификатор для инициаторов и целей iSCSI.' },
  { id: 'lpic2-204-13', topicId: 5, question: 'Какой флаг `hdparm` получает/устанавливает время остановки шпинделя (spindown time) для накопителя?', options: ['-S', '-y', '-Z', '-B'], answer: 0, explanation: '`hdparm -S` устанавливает тайм-аут ожидания (остановки вращения) для накопителя IDE/SATA/SAS.' },
  { id: 'lpic2-204-14', topicId: 5, question: 'В каком файле динамически хранится статус и подробная информация о программных массивах RAID `mdadm`?', options: ['/etc/mdadm.conf', '/proc/mdstat', '/var/log/raid.log', '/sys/block/raid'], answer: 1, explanation: '`/proc/mdstat` предоставляет сводку в реальном времени об аппаратных RAID-массивах ядра и статусе их синхронизации.' },
  { id: 'lpic2-204-15', topicId: 5, question: 'Какой компонент LVM создается непосредственно на необработанном разделе диска (raw partition)?', options: ['Логический том (LV)', 'Группа томов (VG)', 'Физический том (PV)', 'Volume Extent (VE)'], answer: 2, explanation: 'Физический том (PV) — это базовая структура LVM, созданная непосредственно на диске или разделе.' },

  // --- NEW BATCH 2 (Topics 205-208) ---
  { id: 'lpic2-205-6', topicId: 6, question: 'Какая команда `ip` назначает IPv4-адрес 192.168.1.10/24 интерфейсу eth0?', options: ['ip address add 192.168.1.10/24 dev eth0', 'ip addr set eth0 192.168.1.10/24', 'ip assign eth0 192.168.1.10/24', 'ifconfig eth0 add 192.168.1.10/24'], answer: 0, explanation: 'Синтаксис `ip address add <адрес> dev <интерфейс>` является правильным.' },
  { id: 'lpic2-205-7', topicId: 6, question: 'Каково назначение файла `/etc/iproute2/rt_tables`?', options: ['В нем хранится системный кэш ARP', 'Он сопоставляет идентификаторы таблиц маршрутизации с удобочитаемыми именами', 'Он настраивает правила межсетевого экрана для iproute2', 'Он назначает статические IP-адреса'], answer: 1, explanation: 'Этот файл позволяет администраторам использовать символические имена вместо числовых идентификаторов для таблиц маршрутизации политик.' },
  { id: 'lpic2-205-8', topicId: 6, question: 'Какой инструмент в основном используется для настройки параметров (таких как SSID или частота) интерфейса беспроводной сети в Linux?', options: ['ifconfig', 'iwconfig', 'wpa_supplicant', 'nmcli'], answer: 1, explanation: '`iwconfig` — это инструмент CLI, предназначенный для настройки беспроводных расширений и интерфейсов беспроводной сети.' },
  { id: 'lpic2-205-9', topicId: 6, question: 'При проверке подключения, как указать команде `ping` отправлять пакеты именно с интерфейса `eth1`?', options: ['ping -S eth1', 'ping -I eth1', 'ping -e eth1', 'ping -i eth1'], answer: 1, explanation: 'Флаг `-I` явно привязывает сокет ping к определенному интерфейсу или IP-адресу источника.' },
  { id: 'lpic2-205-10', topicId: 6, question: 'Какая команда устанавливает шлюз по умолчанию 10.0.0.1 с использованием набора iproute2?', options: ['ip route add default via 10.0.0.1', 'route add default gw 10.0.0.1', 'ip route default 10.0.0.1', 'ip gw set 10.0.0.1'], answer: 0, explanation: '`ip route add default via <IP>` добавляет правило маршрутизации для шлюза по умолчанию.' },
  { id: 'lpic2-205-11', topicId: 6, question: 'Как захватить сетевые пакеты с помощью tcpdump и сохранить их в файл с именем capture.pcap для последующего анализа в Wireshark?', options: ['tcpdump > capture.pcap', 'tcpdump -f capture.pcap', 'tcpdump -w capture.pcap', 'tcpdump -o capture.pcap'], answer: 2, explanation: 'Флаг `-w` указывает tcpdump записывать исходные пакеты в указанный файл PCAP.' },
  { id: 'lpic2-205-12', topicId: 6, question: 'Какой инструмент Linux часто называют «швейцарским армейским ножом» для сетей, который можно использовать для сканирования портов, передачи файлов и захвата баннеров?', options: ['nmap', 'nc (netcat)', 'telnet', 'curl'], answer: 1, explanation: 'Netcat (`nc`) — универсальная утилита, используемая для чтения и записи в сетевые соединения по TCP или UDP.' },
  { id: 'lpic2-205-13', topicId: 6, question: 'Какой адрес loopback в IPv6 эквивалентен 127.0.0.1?', options: ['::1', 'fe80::1', '0:0:0:0:0:0:0:1', 'И A, и C'], answer: 3, explanation: '`::1` — это сокращенный формат записи для `0:0:0:0:0:0:0:1`, который является адресом localhost в IPv6.' },
  { id: 'lpic2-205-14', topicId: 6, question: 'Какой ключ утилиты `ss` отображает все прослушивающие *и* установленные (не прослушивающие) сокеты?', options: ['ss -l', 'ss -a', 'ss -t', 'ss -u'], answer: 1, explanation: '`ss -a` (all) выводит на экран как прослушивающие, так и не прослушивающие сокеты.' },
  { id: 'lpic2-205-15', topicId: 6, question: 'По умолчанию, пакеты какого типа отправляет традиционная команда Linux `traceroute` для проверки пути?', options: ['TCP SYN', 'ICMP Echo Request', 'UDP-датаграммы', 'Запросы IGMP'], answer: 2, explanation: 'В отличие от Windows `tracert`, который использует ICMP, стандартный Linux `traceroute` использует датаграммы UDP, нацеленные на инкрементно увеличивающиеся высокие номера портов.' },

  { id: 'lpic2-206-6', topicId: 7, question: 'Какая утилита может заменить `make install` для создания пакета Slackware, RPM или Debian из скомпилированного исходного кода для более простого последующего удаления?', options: ['autotools', 'checkinstall', 'dpkg-buildpackage', 'rpmbuild'], answer: 1, explanation: '`checkinstall` отслеживает файлы, установленные `make install`, и создает пакет (например, .deb или .rpm) для чистого управления пакетами.' },
  { id: 'lpic2-206-7', topicId: 7, question: 'Какой инструмент отслеживает вызовы динамических библиотек, выполняемые исполняемым файлом (в отличие от системных вызовов)?', options: ['strace', 'ltrace', 'ldd', 'objdump'], answer: 1, explanation: '`ltrace` перехватывает и записывает вызовы динамических библиотек, привязанных к исполняемому файлу во время выполнения.' },
  { id: 'lpic2-206-8', topicId: 7, question: 'При извлечении архива, сжатого с помощью `bzip2`, какой типичный флаг передается `tar`?', options: ['-z', '-J', '-j', '-b'], answer: 2, explanation: 'Флаг `-j` приказывает GNU tar распаковать архив с использованием bzip2.' },
  { id: 'lpic2-206-9', topicId: 7, question: 'Какая команда управляет операциями накопителя на магнитной ленте, такими как перемотка и извлечение?', options: ['tape', 'mt', 'tar', 'cpio'], answer: 1, explanation: '`mt` (magnetic tape) — стандартная утилита, вызываемая для управления физическими механизмами ленточного накопителя.' },
  { id: 'lpic2-206-10', topicId: 7, question: 'Что делает флаг `-a` (archive) в `rsync`?', options: ['Сжимает данные', 'Выполняет рекурсивную синхронизацию и сохраняет права доступа, время, владельца и символические ссылки', 'Удаляет лишние файлы из места назначения', 'Копирует только скрытые файлы'], answer: 1, explanation: 'Архивный режим (`-a`) эквивалентен `-rlptgoD`, что делает его идеальным флагом для точной синхронизации каталогов.' },
  { id: 'lpic2-206-11', topicId: 7, question: 'Какая команда systemd подает сигнал демону просто перечитать файлы конфигурации без разрыва активных соединений?', options: ['systemctl restart', 'systemctl reload', 'systemctl force-reload', 'systemctl refresh'], answer: 1, explanation: '`reload` безопасно предписывает сервису заново разобрать свои конфиги без жесткого прерывания работы.' },
  { id: 'lpic2-206-12', topicId: 7, question: 'Какова стандартная структура каталогов файловой системы Linux, специально предназначенная для хранения большинства логов сервисов?', options: ['/usr/log/', '/var/spool/log/', '/var/log/', '/etc/logs/'], answer: 2, explanation: 'Каталог `/var/log/` является стандартом (FHS-совместимым) для вывода логов системы и приложений.' },
  { id: 'lpic2-206-13', topicId: 7, question: 'Как подключить `strace` к уже запущенному процессу-демону?', options: ['strace -a <PID>', 'strace -p <PID>', 'strace --attach <PID>', 'strace <PID>'], answer: 1, explanation: 'Флаг `-p` заставляет strace динамически подключаться к указанному Process ID.' },
  { id: 'lpic2-206-14', topicId: 7, question: 'При создании точной побитовой резервной копии раздела диска с помощью `dd`, какой параметр определяет размер порций (chunks), считываемых/записываемых для значительного повышения скорости?', options: ['count=', 'bs=', 'size=', 'chunk='], answer: 1, explanation: '`bs` (block size) диктует количество байтов, считываемых и записываемых за один раз, например: `bs=4M`.' },
  { id: 'lpic2-206-15', topicId: 7, question: 'Какая команда генерирует пару ключей аутентификации OpenSSH?', options: ['ssh-agent', 'ssh-add', 'ssh-keygen', 'ssh-copy-id'], answer: 2, explanation: '`ssh-keygen` математически генерирует пары открытого/закрытого ключей для аутентификации в протоколе SSH.' },

  { id: 'lpic2-207-6', topicId: 8, question: 'В конфигурации зоны BIND, что представляет собой запись SOA?', options: ['Secure Origin Auth', 'Start of Authority', 'Server Origin Address', 'System Oriented Architecture'], answer: 1, explanation: 'Запись Start of Authority (SOA) обязательна в файле зоны и определяет глобальные параметры зоны, такие как TTL и первичный nameserver.' },
  { id: 'lpic2-207-7', topicId: 8, question: 'Для чего в первую очередь используется запись BIND `CNAME`?', options: ['Для делегирования поддомена другой зоне', 'Для назначения почтового сервера', 'Для сопоставления псевдонима с истинным, каноническим именем A или AAAA', 'Для шифрования трафика'], answer: 2, explanation: 'Canonical Name (CNAME) действует как псевдоним, жестко связывающий один домен с другим.' },
  { id: 'lpic2-207-8', topicId: 8, question: 'Какой инструмент можно использовать для интерактивного запроса DNS-сервера или запроса из командной строки для отладки конкретных записей (таких как MX или TXT)?', options: ['named', 'dig', 'ping', 'ipconfig'], answer: 1, explanation: '`dig` (Domain Information Groper) — предпочтительная стандартная утилита для глубоких запросов DNS и устранения неполадок.' },
  { id: 'lpic2-207-9', topicId: 8, question: 'В BIND, какой специальный зарезервированный суффикс используется при определении зоны обратного поиска IPv4 (Reverse Lookup Zone), которая преобразует IP-адреса обратно в имена хостов?', options: ['.local', '.in-addr.arpa', '.ip.reverse', '.arpa.net'], answer: 1, explanation: 'Обратные преобразования IPv4 стандартизированы в специальной иерархии доменов `.in-addr.arpa`.' },
  { id: 'lpic2-207-10', topicId: 8, question: 'Какова роль файла `/etc/resolv.conf`?', options: ['Он настраивает зоны сервера BIND', 'Он определяет, к каким DNS-серверам должна обращаться локальная машина для разрешения имен хостов', 'Он настраивает межсетевой экран', 'Он блокирует вредоносные IP-адреса'], answer: 1, explanation: 'Конфигурационный файл распознавателя (resolver) сообщает сетевому стеку локальной системы, к каким IP-адресам DNS следует обращаться.' },
  { id: 'lpic2-207-11', topicId: 8, question: 'Какая команда BIND очищает кэш DNS и чисто перезагружает зоны без перезапуска демона `named`?', options: ['systemctl restart bind', 'rndc reload', 'named -reload', 'bind-flush'], answer: 1, explanation: '`rndc` — утилита дистанционного управления демоном BIND; `rndc reload` чисто перечитывает конфиг и зоны.' },
  { id: 'lpic2-207-12', topicId: 8, question: 'В DNSSEC, что такое запись DS?', options: ['Domain Signature', 'Delegation Signer', 'Digital Security', 'Data Synchronizer'], answer: 1, explanation: 'Запись Delegation Signer (DS) публикуется в родительской зоне для установления цепочки доверия (chain of trust) к дочерней зоне.' },
  { id: 'lpic2-207-13', topicId: 8, question: 'Какой механизм чаще всего используется в BIND для криптографической защиты и авторизации передачи зон (AXFR) между master и slave DNS-серверами?', options: ['DNSSEC', 'TSIG', 'TLS', 'IPsec'], answer: 1, explanation: 'Transaction Signature (TSIG) использует общие секретные ключи для безопасной аутентификации связи между DNS-серверами.' },
  { id: 'lpic2-207-14', topicId: 8, question: 'В SOA записи BIND, каково назначение "Серийного номера" (Serial Number)?', options: ['Указывает количество доменов в зоне', 'Однозначно идентифицирует аппаратное обеспечение сервера', 'Сообщает подчиненным (slave) серверам, устарел ли их кэшированный файл зоны и нужна ли синхронизация', 'Действует как ключ шифрования'], answer: 2, explanation: 'Вторичные серверы проверяют серийный номер; если серийный номер первичного сервера выше, инициируется передача (transfer) зоны.' },
  { id: 'lpic2-207-15', topicId: 8, question: 'При защите BIND общепринятой передовой практикой является запуск процесса `named` в строго ограниченной среде. Как называется этот метод защиты?', options: ['Контейнеризация (Containerization)', 'Chroot Jail («Тюрьма» chroot)', 'Инкапсуляция VPN', 'Отключенный SELinux'], answer: 1, explanation: 'Chrooting (Change Root) ограничивает процесс BIND определенным подкаталогом, не позволяя ему получить доступ к корневой системе в случае компрометации.' },

  { id: 'lpic2-208-6', topicId: 9, question: 'Какая директива в конфигурации Apache указывает основной каталог, из которого предоставляются файлы для домена?', options: ['ServerRoot', 'DocumentRoot', 'DirectoryIndex', 'WebRoot'], answer: 1, explanation: '`DocumentRoot` указывает на физический путь к каталогу, где находятся HTML-файлы.' },
  { id: 'lpic2-208-7', topicId: 9, question: 'Какая директива Nginx критически важна для реализации обратного прокси-сервера к серверу приложений бэкенда?', options: ['fastcgi_pass', 'server_name', 'proxy_pass', 'location_root'], answer: 2, explanation: '`proxy_pass` явно перенаправляет HTTP-запросы к проксируемому внутреннему серверу (например, к экземпляру Node.js или Tomcat).' },
  { id: 'lpic2-208-8', topicId: 9, question: 'Чего достигает модуль Apache `mod_rewrite`?', options: ['Переводит языки на лету', 'Сжимает данные HTML', 'Динамически анализирует и перезаписывает запросы URL на основе правил регулярных выражений', 'Предотвращает SQL-инъекции'], answer: 2, explanation: '`mod_rewrite` — это продвинутый механизм манипулирования URL-адресами, маршрутизирующий URL к определенным контроллерам.' },
  { id: 'lpic2-208-9', topicId: 9, question: 'Для чего используется файл `.htaccess` в Apache?', options: ['Для хранения зашифрованных паролей', 'Для определения глобальных лимитов сервера', 'Чтобы разрешить децентрализованное переопределение конфигурации на уровне каталога без редактирования конфигурации главного сервера', 'Для блокировки запросов ping'], answer: 2, explanation: 'Это децентрализованный файл конфигурации, позволяющий разработчикам применять правила (например, rewrites) непосредственно в каталоге.' },
  { id: 'lpic2-208-10', topicId: 9, question: 'В Squid вы пишете: `acl LAN src 192.168.1.0/24`. Что нужно сделать, чтобы фактически запретить трафик в эту LAN?', options: ['http_access allow LAN', 'http_access deny LAN', 'squid_deny LAN', 'acl deny LAN'], answer: 1, explanation: 'ACL лишь определяет группу. Затем требуется правило `http_access`, чтобы явно разрешить (`allow`) или запретить (`deny`) доступ для этого ACL.' },
  { id: 'lpic2-208-11', topicId: 9, question: 'С точки зрения архитектуры, почему Nginx исторически обрабатывает огромное количество одновременных подключений эффективнее, чем стандартный MPM Prefork в Apache?', options: ['Nginx выполняет более быстрый код C', 'Nginx использует асинхронную, управляемую событиями неблокирующую архитектуру', 'В Apache отсутствуют механизмы кэширования', 'Nginx использует UDP'], answer: 1, explanation: 'Цикл событий (event loop) Nginx легко жонглирует тысячами соединений в одном потоке, избегая накладных расходов на порождение процессов.' },
  { id: 'lpic2-208-12', topicId: 9, question: 'В Squid, что такое кеш "parent" (родитель)?', options: ['Сервер базы данных бэкенда', 'Другой прокси-сервер, на который Squid перенаправляет трафик в случае промаха в кеше (cache-miss), запрашивая у него получение объекта', 'IP-адрес шлюза по умолчанию', 'Балансировщик нагрузки'], answer: 1, explanation: 'Родительский кэш разрешает интернет-запросы от имени дочернего сервера Squid в иерархии прокси.' },
  { id: 'lpic2-208-13', topicId: 9, question: 'Какая основная директива конфигурации Nginx обычно соответствует количеству ядер ЦП для максимизации производительности?', options: ['max_connections', 'worker_processes', 'server_workers', 'events'], answer: 1, explanation: 'Использование `worker_processes auto;` или установка значения, равного числу ядер процессора, позволяет Nginx полностью задействовать аппаратные средства ЦП.' },
  { id: 'lpic2-208-14', topicId: 9, question: 'Какая директива Apache в блоке `<VirtualHost>` определяет доменные имена, на которые будет отвечать Host?', options: ['DNSName', 'Hostname', 'ServerName и ServerAlias', 'Domain'], answer: 2, explanation: '`ServerName` назначает основной домен, а `ServerAlias` указывает альтернативные имена хостов.' },
  { id: 'lpic2-208-15', topicId: 9, question: 'Что делает команда `squid -k reconfigure`?', options: ['Внезапно убивает процесс squid', 'Полностью очищает кэш', 'Отправляет сигнал работающему процессу Squid на перезагрузку файла squid.conf без отключения клиентов', 'Скачивает обновления'], answer: 2, explanation: 'Аналогично перезагрузке (reload) Nginx или systemctl, `-k reconfigure` — это безопасный способ применения изменений конфигурации Squid.' },

  // --- NEW BATCH 3 (Topics 209-212) ---
  { id: 'lpic2-209-6', topicId: 10, question: 'В конфигурации Samba (`smb.conf`), что означает параметр `security = user`?', options: ['Заставляет Samba использовать зашифрованные пароли', 'Требует, чтобы клиенты аутентифицировались с действительным именем пользователя и паролем перед доступом к общим ресурсам', 'Делает общий ресурс доступным только для чтения', 'Отключает гостевой доступ во всем мире'], answer: 1, explanation: '`security = user` — наиболее распространенный режим автономной работы, обязывающий использовать аутентификацию на уровне пользователя для каждого подключения.' },
  { id: 'lpic2-209-7', topicId: 10, question: 'Какая команда используется для сопоставления (маппинга) существующих локальных пользователей Linux с их паролями Samba для аутентификации SMB?', options: ['smbpasswd -a <пользователь>', 'useradd -s /bin/smb', 'pdbedit -L', 'smbclient -U'], answer: 0, explanation: 'Команда `smbpasswd -a` добавляет локального пользователя Linux во внутреннюю базу данных паролей Samba.' },
  { id: 'lpic2-209-8', topicId: 10, question: 'При монтировании общего ресурса NFS на стороне клиента, какая опция монтирования в `/etc/fstab` (часто используемая по умолчанию в современных системах) позволяет клиенту корректно обрабатывать недоступность сервера без зависания процессов на неопределенный срок?', options: ['hard', 'soft', 'intr', 'sync'], answer: 0, explanation: 'Монтирование `hard` заставляет процессы приостанавливаться (sleep) в ожидании восстановления сервера, гарантируя целостность данных (в отличие от `soft`, который прерывает операции с ошибкой I/O).' },
  { id: 'lpic2-209-9', topicId: 10, question: 'Какая служебная программа командной строки Linux работает как FTP-клиент, позволяя обмениваться файлами с сервером Samba/Windows SMB в интерактивном режиме?', options: ['smbtree', 'nmblookup', 'smbclient', 'mount.cifs'], answer: 2, explanation: '`smbclient` предоставляет интерактивную оболочку в стиле FTP для доступа и передачи файлов по протоколу SMB/CIFS.' },
  { id: 'lpic2-209-10', topicId: 10, question: 'В конфигурации экспорта NFS (`/etc/exports`), что делает опция `no_root_squash`?', options: ['Блокирует доступ пользователя root', 'Сжимает владельца файла до UID 0', 'Разрешает удаленным пользователям root действовать с привилегиями root в экспортированном каталоге', 'Предотвращает запись файлов'], answer: 2, explanation: 'По умолчанию, NFS понижает привилегии клиентского пользователя root до "nobody" (root_squash). `no_root_squash` позволяет клиенту сохранить реальные права пользователя root.' },
  { id: 'lpic2-209-11', topicId: 10, question: 'Какой инструмент диагностирует конфигурационные файлы Samba и проверяет их на наличие синтаксических ошибок?', options: ['smbstatus', 'testparm', 'wbinfo', 'nmbd'], answer: 1, explanation: 'Утилита `testparm` проверяет `smb.conf` на корректность работы и выводит отчет о фактических примененных настройках.' },
  { id: 'lpic2-209-12', topicId: 10, question: 'На серверах NFSv3, какой вспомогательный демон отвечает за прослушивание портов и регистрацию RPC-сервисов?', options: ['nfsd', 'rpcbind (или portmap)', 'mountd', 'statd'], answer: 1, explanation: '`rpcbind` (ранее portmap) сопоставляет номера программ RPC с номерами сетевых портов.' },
  { id: 'lpic2-209-13', topicId: 10, question: 'Какова основная цель демона Samba `nmbd`?', options: ['Предоставление сервисов совместного использования файлов и принтеров', 'Служба разрешения NetBIOS имен и просмотр (browsing)', 'Интеграция с Active Directory', 'Аутентификация по протоколу Kerberos'], answer: 1, explanation: 'В то время как `smbd` управляет файлами/принтерами, `nmbd` отвечает за разрешения имен NetBIOS-над-TCP/IP и "Сетевое окружение" (network browsing).' },
  { id: 'lpic2-209-14', topicId: 10, question: 'Какая команда на NFS-сервере заставляет ядро перечитать файл `/etc/exports` и немедленно применить изменения без перезапуска демона NFS?', options: ['exportfs -a', 'exportfs -r', 'systemctl reload nfs', 'Оба варианта (B и C)'], answer: 3, explanation: '`exportfs -r` синхронизирует списки экспорта ядра с файлом `/etc/exports`.' },
  { id: 'lpic2-209-15', topicId: 10, question: 'В Samba, какой параметр устанавливает имя Windows-подобной рабочей группы (Workgroup), к которой принадлежит сервер?', options: ['netbios name =', 'workgroup =', 'domain =', 'server string ='], answer: 1, explanation: 'Директива `workgroup = WORKGROUP_NAME` в секции `[global]` определяет этот параметр.' },

  { id: 'lpic2-210-6', topicId: 11, question: 'Какую основную роль выполняет протокол DHCP в сети?', options: ['Перенаправляет сетевой трафик', 'Разрешает имена хостов в IP-адреса', 'Динамически назначает IP-адреса, маски подсети и шлюзы клиентам сетей', 'Аутентифицирует беспроводных пользователей'], answer: 2, explanation: 'DHCP (Dynamic Host Configuration Protocol) автоматизирует распределение сетевых настроек хостам.' },
  { id: 'lpic2-210-7', topicId: 11, question: 'Какая последовательность пакетов завершает успешную аренду (lease) IPv4 DHCP?', options: ['SYN, SYN-ACK, ACK', 'DISCOVER, OFFER, REQUEST, ACK (DORA)', 'HELO, MAIL FROM, RCPT TO, DATA', 'REQUEST, REPLY, ACK'], answer: 1, explanation: 'Процесс DORA: клиент Discover, сервер Offer, клиент Request, сервер Acknowledge.' },
  { id: 'lpic2-210-8', topicId: 11, question: 'При развертывании DHCP-сервера ISC, где обычно находится основной конфигурационный файл (до версии Kea)?', options: ['/etc/dhcp/dhcpd.conf', '/etc/dhcpd/dhcpd.conf', '/etc/bind/dhcp.conf', '/var/lib/dhcp/dhcpd.conf'], answer: 0, explanation: 'Историческим местоположением по умолчанию для конфигурации демона ISC DHCP является `/etc/dhcp/dhcpd.conf`.' },
  { id: 'lpic2-210-9', topicId: 11, question: 'Как в `dhcpd.conf` зарезервировать определенный IP-адрес для конкретного MAC-адреса устройства (например, принтера)?', options: ['Используя резервацию `static-ip`', 'Указывая объявление `host { hardware ethernet ...; fixed-address ...; }`', 'Устанавливая `mac-reserve`', 'Используя `address-bind`'], answer: 1, explanation: 'Блок `host` связывает MAC-адрес устройства напрямую с определенной директивой `fixed-address`.' },
  { id: 'lpic2-210-10', topicId: 11, question: 'Для чего используется агент ретрансляции DHCP (DHCP Relay Agent, dhcrelay)?', options: ['Шифрует трафик DHCP', 'Действует как резервный DHCP-сервер', 'Пересылает широковещательные запросы DHCPD между подсетями к централизованному DHCP-серверу', 'Не позволяет несанкционированным серверам предлагать IP-адреса'], answer: 2, explanation: 'Маршрутизаторы не пересылают широковещательный трафик (broadcast). Релейные агенты принимают широковещательные рассылки DORA и перенаправляют их по принципу unicast на сервер DHCP в другой подсети.' },
  { id: 'lpic2-210-11', topicId: 11, question: 'Какое программное обеспечение PAM-модуля широко используется в Linux для бесшовной аутентификации пользователей с помощью серверов Windows Active Directory или LDAP?', options: ['NIS+', 'winbind', 'SSSD (System Security Services Daemon)', 'Samba-DC'], answer: 2, explanation: 'SSSD является предпочтительным современным демоном для подключения Linux-машин к удаленным службам каталогов (LDAP, AD, FreeIPA) для аутентификации PAM и NSS.' },
  { id: 'lpic2-210-12', topicId: 11, question: 'В конфигурационном файле PAM (например, `/etc/pam.d/system-auth`), что означает управляющий флаг `required`?', options: ['Успешная аутентификация модуля достаточна для одобрения, если предыдущие модули passed', 'Сбой модуля в конечном итоге приводит к отказу в аутентификации, но PAM продолжает вызывать остальные модули в стеке', 'Сбой модуля мгновенно отклоняет попытку аутентификации', 'Модуль является необязательным'], answer: 1, explanation: '`required` требует, чтобы модуль был успешным, но в случае неудачи он не сообщает пользователю об этом немедленно; стек продолжает работу так же, как если бы все было в порядке, чтобы не выдать причину отказа.' },
  { id: 'lpic2-210-13', topicId: 11, question: 'Где находится основной конфигурационный файл сервера LDAP (исторически OpenLDAP)?', options: ['/etc/openldap/slapd.conf', '/etc/ldap/slapd.conf (или /etc/ldap/slapd.d/)', 'Оба варианта (в зависимости от дистрибутива)', '/var/lib/ldap/config'], answer: 2, explanation: 'Конфигурация OpenLDAP находится в `slapd.conf` (или в более современном динамическом каталоге конфигураций `cn=config` в `slapd.d`).' },
  { id: 'lpic2-210-14', topicId: 11, question: 'Какова цель LDAP `slapcat`?', options: ['Для просмотра текущих подключений LDAP', 'Для экспорта/резервного копирования базы данных LDAP в текстовый файл LDIF, даже когда сервер работает в автономном режиме', 'Для импорта пользователей в LDAP', 'Для шифрования паролей LDAP'], answer: 1, explanation: '`slapcat` читает базу данных напрямую, минуя демон slapd, и генерирует вывод LDIF.' },
  { id: 'lpic2-210-15', topicId: 11, question: 'Что означает `dn` в LDAP?', options: ['Domain Naming', 'Directory Node', 'Distinguished Name', 'Data Network'], answer: 2, explanation: 'Distinguished Name (DN) — это строка, которая однозначно идентифицирует запись LDAP и описывает ее положение на дереве инфо-каталога DIT.' },

  { id: 'lpic2-211-6', topicId: 12, question: 'Какова основная функция Postfix или Sendmail?', options: ['MUA (Mail User Agent)', 'POP3 Server', 'MTA (Mail Transfer Agent)', 'IMAP Server'], answer: 2, explanation: 'MTA (Агенты передачи сообщений) отвечают за маршрутизацию и доставку электронной почты по протоколу SMTP с сервера на сервер.' },
  { id: 'lpic2-211-7', topicId: 12, question: 'Где хранятся основные конфигурационные файлы для Postfix?', options: ['/etc/mail/', '/etc/postfix/', '/var/spool/postfix/', '/usr/local/postfix/'], answer: 1, explanation: 'Каталог `/etc/postfix/` содержит такие файлы как `main.cf` и `master.cf`.' },
  { id: 'lpic2-211-8', topicId: 12, question: 'В конфигурации Postfix (`main.cf`), какую цель служит директива `mynetworks`?', options: ['Она определяет Интернет-домен сервера', 'Список доверенных IP-адресов/подсетей, которым разрешено пересылать (relay) почту через этот сервер без аутентификации', 'Она блокирует спамеров', 'Она настраивает параметры IMAP'], answer: 1, explanation: 'Подключенные из этих доверенных сетей могут использовать SMTP-сервер для отправки исходящих писем внешним получателям.' },
  { id: 'lpic2-211-9', topicId: 12, question: 'Какая команда используется для перестройки (rebuild) хэшированных файлов баз данных Postfix, например `/etc/postfix/aliases`?', options: ['postfix reload', 'postmap /etc/postfix/aliases (или newaliases)', 'makemap hash', 'hashmail'], answer: 1, explanation: 'Команда `newaliases` или `postmap` берет текстовый файл и строит проиндексированную базу данных (например, aliases.db), понятную демону Postfix.' },
  { id: 'lpic2-211-10', topicId: 12, question: 'Что делает Procmail (или более современные решения вроде Sieve)?', options: ['Действует как MTA', 'Действует как MDA (Mail Delivery Agent), сортируя и фильтруя входящую электронную почту в почтовые ящики пользователей на основе правил', 'Обслуживает клиентские запросы POP3', 'Сканирует систему на наличие руткитов'], answer: 1, explanation: 'MDA получает письма от MTA и применяет локальные правила (маршрутизация по папкам, обработка спама, автоответчики) для конкретного пользователя.' },
  { id: 'lpic2-211-11', topicId: 12, question: 'В чем ключевое различие между протоколами электронной почты IMAP и POP3?', options: ['POP3 скачивает заголовки, а IMAP — всю электронную почту', 'IMAP обычно оставляет почту на сервере и синхронизирует состояние, POP3 обычно загружает и удаляет из сервера', 'POP3 использует порт 143, IMAP использует 110', 'IMAP поддерживает только формат Maildir'], answer: 1, explanation: 'IMAP разработан для синхронизации папок электронной почты между несколькими клиентами. POP3 по своей сути является протоколом простой загрузки (скачивания).' },
  { id: 'lpic2-211-12', topicId: 12, question: 'Какой порт резервируется для защищенного протокола SMTPS (SMTP через TLS/SSL) или зашифрованной отправки сообщений клиентами?', options: ['25', '110', '143', '465 или 587'], answer: 3, explanation: 'Порт 25 предназначен для межсерверной передачи данных без шифрования. Разработчики MUA-клиентов используют порт 465 (явный SSL/TLS) или 587 (явный старт STARTTLS) для безопасной аутентификации и отправки писем.' },
  { id: 'lpic2-211-13', topicId: 12, question: 'Какая команда Postfix выводит на экран все сообщения, которые в данный момент ожидают отправки в очереди маршрутизации сервера (mail queue)?', options: ['mailq', 'postqueue -p', 'Оба варианта (A и B)', 'showq'], answer: 2, explanation: 'Команды `mailq` (наследие Sendmail) и `postqueue -p` показывают одну и ту же информацию об элементах, находящихся в очереди Postfix.' },
  { id: 'lpic2-211-14', topicId: 12, question: 'Какова цель формата хранения почты "Maildir" (в отличие от "mbox")?', options: ['Сжатие всех писем в один файл для экономии места', 'Хранение каждого письма в виде отдельного файла, что предотвращает блокировку файлов и повышает скорость работы почтовых клиентов', 'Хранение почты в базе данных SQL', 'Шифрование всей почты'], answer: 1, explanation: 'Формат `mbox` сохраняет все в одном гигантском текстовом файле. `Maildir` хранит каждое письмо отдельно, обеспечивая превосходную производительность и надежность.' },
  { id: 'lpic2-211-15', topicId: 12, question: 'Где перенаправления пользователей (aliases), находящиеся в `/etc/aliases`, перенаправляют электронную почту по умолчанию, если они не указаны в файле?', options: ['Письма отклоняются', 'Письма доставляются пользователю root', 'Они доставляются в локальный ящик на основе системного логина (username)', 'Отправляются администратору postmaster'], answer: 2, explanation: 'При отсутствии правил перенаправления (алиасов), почта на имя `<user>@localhost` доставляется в локальный почтовый ящик пользователя в `/var/mail/<user>` или `~/Maildir/`.' },

  { id: 'lpic2-212-6', topicId: 13, question: 'В Nmap, что делает флаг сканирования `-sS`?', options: ['Выполняет полное TCP-сканирование через Connect()', 'Выполняет UDP-сканирование', 'Выполняет TCP SYN-сканирование («полуоткрытое», stealth scan)', 'Сканирует версии сервисов'], answer: 2, explanation: 'SYN-сканирование отправляет пакет с флагом SYN, ожидает SYN-ACK, но отправляет RST, не дожидаясь полного завершения TCP handshake, что делает его менее заметным в старых логах.' },
  { id: 'lpic2-212-7', topicId: 13, question: 'Где находится основной пользовательский конфигурационный файл демона SSH (`sshd`)?', options: ['/etc/ssh/ssh_config', '/etc/sshd.conf', '/etc/ssh/sshd_config', '/var/lib/sshd/config'], answer: 2, explanation: '`sshd_config` настраивает параметры сервера (демона). (`ssh_config` настраивает исходящий клиент).' },
  { id: 'lpic2-212-8', topicId: 13, question: 'Какая директива в `sshd_config` запрещает пользователю root входить в систему напрямую через SSH?', options: ['PermitRootLogin no', 'DenyUsers root', 'RootAccess false', 'DisableRoot yes'], answer: 0, explanation: 'Переменная `PermitRootLogin no` — важный и настоятельно рекомендуемый совет по безопасности, запрещающий входы от имени root. Администраторы должны аутентифицироваться под обычным пользователем и использовать `sudo`.' },
  { id: 'lpic2-212-9', topicId: 13, question: 'Что делает команда `ipsec verify` в реализации StrongSwan/Libreswan?', options: ['Запускает туннель', 'Выполняет проверку работоспособности установленных пакетов, конфигураций и маршрутов системы IPSec', 'Резервирует базу данных ключей', 'Тестирует брандмауэр'], answer: 1, explanation: 'Это автономная тестовая утилита для проверки того, что ядро, сетевые интерфейсы, и сервисы правильно настроены для работы IPsec.' },
  { id: 'lpic2-212-10', topicId: 13, question: 'Как в `iptables` сохранить правила межсетевого экрана (firewall), чтобы они восстанавливались после перезагрузки в системах на базе Debian?', options: ['iptables-save > /etc/iptables/rules.v4', 'service iptables save', 'iptables-commit', 'iptables --persistent'], answer: 0, explanation: 'Обычно используется пакет `iptables-persistent`. Администраторы сбрасывают текущие правила и направляют вывод в `rules.v4` и `rules.v6`, которые перечитываются при загрузке.' },
  { id: 'lpic2-212-11', topicId: 13, question: 'В iptables, какая таблица (table) в основном используется для манипулирования (изменения) адресов или портов пакетов (например, Source NAT или маскарадинг)?', options: ['filter', 'mangle', 'nat', 'raw'], answer: 2, explanation: 'Таблица `nat` (Network Address Translation) специально создана для изменения IP-адресов источника (`SNAT`) или назначения (`DNAT`).' },
  { id: 'lpic2-212-12', topicId: 13, question: 'Какая команда OpenVPN используется для генерации статического разделяемого секретного ключа (pre-shared key, PSK) для базового туннеля типа "точка-точка"?', options: ['openvpn --genkey tls-auth ta.key', 'openvpn --genkey secret secret.key', 'openssl genrsa', 'vpnkey-gen'], answer: 1, explanation: 'Флаги `--genkey secret` создают файл со статическим симметричным ключом (обычно используется для небольших, не-PKI инсталляций).' },
  { id: 'lpic2-212-13', topicId: 13, question: 'Какой порт/протокол по умолчанию использует OpenVPN?', options: ['TCP 443', 'UDP 1194', 'TCP 80', 'IP протокол 50 (ESP)'], answer: 1, explanation: 'По умолчанию OpenVPN слушает порт 1194 по UDP для оптимальной производительности, хотя может быть без вреда перенастроен и на TCP-соединения.' },
  { id: 'lpic2-212-14', topicId: 13, question: 'Что указывает цель `-j REJECT` в iptables в отличие от `-j DROP`?', options: ['REJECT заносит пакет в лог, DROP не заносит', 'REJECT отсылает обратно ICMP-ответ об ошибке (например, "порт недоступен"), тогда как DROP просто отбрасывает пакет', 'REJECT используется для исходящего трафика, DROP — для входящего', 'Они полностью идентичны'], answer: 1, explanation: '`REJECT` вежливо уведомляет отправителя о том, что соединение было активно отклонено, что ускоряет время ожидания (drop/stealth заставляет отправителя ждать окончания тайм-аута).' },
  { id: 'lpic2-212-15', topicId: 13, question: 'Что делает команда `fail2ban-client status sshd`?', options: ['Отображает текущий статус "тюрьмы" sshd, включая количество неудачных попыток и количество в данный момент заблокированных IP-адресов', 'Отправляет тестовую неверную попытку аутентификации в SSH', 'Перезапускает демона sshd', 'Снимает блокировку со всех IP-адресов'], answer: 0, explanation: 'Инструмент Fail2Ban command-line tool (`fail2ban-client`) предоставляет оперативную статистику в реальном времени, измеряя, насколько активно конкретный сервис атакуют.' }
]
